[{"category":"section","location":"#FastGradientProjection","page":"Home","text":"Documentation for FastGradientProjection.\n\n","title":"FastGradientProjection"},{"category":"method","location":"#FastGradientProjection.FGP!-Union{Tuple{T}, Tuple{AbstractMatrix{T}, Any, Any}} where T","page":"Home","text":"FGP!(b, λ, N; lower_bound=-Inf, upper_bound=Inf, TV=\"iso\")\n\nSame as FGP, but operates in-place on b.\n\n\n\n\n\n","title":"FastGradientProjection.FGP!"},{"category":"method","location":"#FastGradientProjection.FGP-Union{Tuple{T}, Tuple{AbstractMatrix{T}, Any, Any}} where T","page":"Home","text":"FGP(b, λ, N; lower_bound=-Inf, upper_bound=Inf, TV=\"iso\")\n\nreturn denoised (volume) image b based on the minimization problem min_mathbfxinCmathbfx - mathbfb^2_F + 2lambdamathrmTV(mathbfx)\n\nArguments\n\nb: input (volume) image.\nλ: regularization parameter.\nN: number of iterations.\nlower_bound=-Inf: upper bound of the convex closed set C. If b is a complex array, projection to C is not performed.\nupper_bound=Inf: lower bound of the convex closed set C.\nTV=\"iso\": if TV=\"iso\" (default), denoising is based on isotropic TV. To specify anisotropic TV, set TV=\"aniso\".\n\n\n\n\n\n","title":"FastGradientProjection.FGP"},{"category":"method","location":"#FastGradientProjection.GP!-Union{Tuple{T}, Tuple{AbstractMatrix{T}, Any, Any}} where T","page":"Home","text":"GP!(b, λ, N; lower_bound=-Inf, upper_bound=Inf, TV=\"iso\")\n\nSame as GP, but operates in-place on b.\n\n\n\n\n\n","title":"FastGradientProjection.GP!"},{"category":"method","location":"#FastGradientProjection.GP-Union{Tuple{T}, Tuple{AbstractMatrix{T}, Any, Any}} where T","page":"Home","text":"GP(b, λ, N; lower_bound=-Inf, upper_bound=Inf, TV=\"iso\")\n\nreturn denoised (volume) image b. Compared to FGP, convergence is slower, but memory usage is lower.\n\n\n\n\n\n","title":"FastGradientProjection.GP"}]
